const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;

  // Handle both nested and flat structures
  const fields = raw.fields || raw;

  // Safely extract all fields
  const title = (fields.Title ?? fields.title ?? "").toString().trim();
  const issue = (fields.Issue ?? fields.issue ?? "").toString().trim();
  const status = (fields.Status ?? fields.status ?? "").toString().trim();
  const user = (fields.User ?? fields.user ?? "").toString().trim();
  const customerEmail = (fields["Customer Email"] ?? fields.customerEmail ?? "").toString().trim();
  const priority = (fields.Priority ?? fields.priority ?? "").toString().trim();
  const dateSubmitted = (fields["Date Submitted"] ?? fields.dateSubmitted ?? "").toString().trim();
  const ticketId = (fields["Ticket ID"] ?? fields.ticketId ?? "").toString().trim();
  const recordId = raw.id ?? fields.id ?? "";

  // Validation
  const titleValid = title.length > 0;
  const issueValid = issue.length > 0;
  const statusValid = status === "New" || status === "Processing";
  const isValid = titleValid && issueValid && statusValid;

  results.push({
    json: {
      id: recordId,
      ticketId: ticketId,
      title: title,
      issue: issue,
      status: status,
      user: user,
      customerEmail: customerEmail,
      priority: priority,
      dateSubmitted: dateSubmitted,
      isValid: isValid,
      debug_titleValid: titleValid,
      debug_issueValid: issueValid,
      debug_statusValid: statusValid
    }
  });
}

return results;

