const items = $input.all();
const results = [];

for (const item of items) {
  // Get raw response from Groq
  let rawContent = item.json.choices?.[0]?.message?.content || "";

  let parsed = {};
  let parseSuccess = false;

  // Clean the raw content first
  let cleaned = rawContent
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  // Attempt 1: Parse directly
  try {
    parsed = JSON.parse(cleaned);
    parseSuccess = true;
  } catch (e1) {

    // Attempt 2: Find JSON object using regex
    try {
      const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        parsed = JSON.parse(jsonMatch[0]);
        parseSuccess = true;
      }
    } catch (e2) {

      // Attempt 3: Fix unescaped newlines inside string values
      try {
        const fixed = cleaned
          .replace(/:\s*"([\s\S]*?)"/g, (match, p1) => {
            const fixedValue = p1
              .replace(/\n/g, "\\n")
              .replace(/\r/g, "\\r")
              .replace(/\t/g, "\\t");
            return `: "${fixedValue}"`;
          });
        parsed = JSON.parse(fixed);
        parseSuccess = true;
      } catch (e3) {

        // Attempt 4: Manually extract each field using regex
        try {
          const extract = (field) => {
            const regex = new RegExp(`"${field}"\\s*:\\s*"([\\s\\S]*?)"(?=\\s*,\\s*"|\\s*\\})`);
            const match = cleaned.match(regex);
            return match ? match[1].replace(/\\n/g, "\n") : "";
          };

          parsed = {
            summary: extract("summary"),
            priority: extract("priority"),
            priority_reason: extract("priority_reason"),
            email_subject: extract("email_subject"),
            email_content: extract("email_content"),
            suggested_reply: extract("suggested_reply"),
            estimated_resolution: extract("estimated_resolution")
          };

          // Check if we got at least summary
          if (parsed.summary) {
            parseSuccess = true;
          }
        } catch (e4) {
          parseSuccess = false;
        }
      }
    }
  }

  // Final fallback
  if (!parseSuccess || !parsed.summary) {
    parsed = {
      summary: "Could not parse AI response",
      priority: "Medium",
      priority_reason: "Default priority due to parsing error",
      email_subject: "New Support Ticket Received",
      email_content: cleaned,
      suggested_reply: "Thank you for contacting support.",
      estimated_resolution: "Unknown"
    };
  }

  results.push({
    json: {
      summary: parsed.summary || "",
      priority: parsed.priority || "Medium",
      priority_reason: parsed.priority_reason || "",
      email_subject: parsed.email_subject || "",
      email_content: parsed.email_content || "",
      suggested_reply: parsed.suggested_reply || "",
      estimated_resolution: parsed.estimated_resolution || ""
    }
  });
}

return results;

